/**
 * Tests for pptx-to-images.ts
 *
 * Testa o módulo de conversão de PPTX para imagens de slide.
 * Como LibreOffice/pdftoppm não estão disponíveis neste ambiente,
 * os testes validam:
 *  - O tratamento de erro quando binários não existem
 *  - A interface/contrato do módulo
 *  - A validação de arquivo de entrada
 */

import { convertPresentationToImages, checkConversionDependencies } from '@/lib/pptx/pptx-to-images';
import * as fs from 'fs/promises';
import * as path from 'path';
import * as os from 'os';

describe('pptx-to-images', () => {
  describe('checkConversionDependencies', () => {
    it('should return status of system dependencies', async () => {
      const result = await checkConversionDependencies();

      expect(result).toHaveProperty('libreoffice');
      expect(result).toHaveProperty('pdftoppm');
      expect(result).toHaveProperty('ready');
      expect(result).toHaveProperty('message');
      expect(typeof result.libreoffice).toBe('boolean');
      expect(typeof result.pdftoppm).toBe('boolean');
      expect(typeof result.ready).toBe('boolean');
      expect(typeof result.message).toBe('string');

      // If both are installed, ready should be true
      if (result.libreoffice && result.pdftoppm) {
        expect(result.ready).toBe(true);
        expect(result.message).toBe('All dependencies available');
      } else {
        expect(result.ready).toBe(false);
        expect(result.message).toContain('Missing dependencies');
      }
    });
  });

  describe('convertPresentationToImages', () => {
    it('should return error for non-existent input file', async () => {
      const result = await convertPresentationToImages('/nonexistent/file.pptx');

      expect(result.success).toBe(false);
      expect(result.images).toEqual([]);
      expect(result.totalSlides).toBe(0);
      expect(result.error).toContain('Input file not found');
    });

    it('should handle missing LibreOffice gracefully', async () => {
      // Create a temporary file to pass the file-exists check
      const tmpDir = await fs.mkdtemp(path.join(os.tmpdir(), 'pptx-test-'));
      const tmpFile = path.join(tmpDir, 'test.pptx');
      await fs.writeFile(tmpFile, 'fake-pptx-content');

      try {
        const result = await convertPresentationToImages(tmpFile);

        // If LibreOffice is not installed, should get a clear error
        if (!result.success) {
          expect(result.error).toBeDefined();
          expect(result.images).toEqual([]);
          expect(result.totalSlides).toBe(0);
          // Error should mention either LibreOffice or pdftoppm
          const errorLower = (result.error ?? '').toLowerCase();
          const mentionsDependency =
            errorLower.includes('libreoffice') ||
            errorLower.includes('pdftoppm') ||
            errorLower.includes('not installed');
          expect(mentionsDependency).toBe(true);
        }
      } finally {
        await fs.rm(tmpDir, { recursive: true, force: true });
      }
    });

    it('should accept custom conversion options', async () => {
      const tmpDir = await fs.mkdtemp(path.join(os.tmpdir(), 'pptx-test-'));
      const tmpFile = path.join(tmpDir, 'test.pptx');
      await fs.writeFile(tmpFile, 'fake-pptx-content');

      try {
        const result = await convertPresentationToImages(tmpFile, {
          width: 1280,
          height: 720,
          dpi: 96,
          format: 'jpeg',
          timeoutMs: 30_000,
        });

        // Should handle gracefully regardless of dependencies
        expect(result).toHaveProperty('success');
        expect(result).toHaveProperty('images');
        expect(result).toHaveProperty('totalSlides');
      } finally {
        await fs.rm(tmpDir, { recursive: true, force: true });
      }
    });

    it('should return proper SlideImage structure when successful', async () => {
      // This test documents the expected interface
      const depsCheck = await checkConversionDependencies();

      if (!depsCheck.ready) {
        // Can't test full conversion without dependencies — just verify interface
        const result = await convertPresentationToImages('/nonexistent.pptx');
        expect(result).toMatchObject({
          success: false,
          images: [],
          totalSlides: 0,
        });
        return;
      }

      // If dependencies ARE available, we'd test with a real PPTX here
      // Skipping actual conversion test in CI without LibreOffice
    });
  });
});
